sql_examples.sql:
-- 1단계: NOMOUNT (인스턴스만 시작)
STARTUP NOMOUNT;

-- 2단계: MOUNT (컨트롤 파일 오픈)
ALTER DATABASE MOUNT;

-- 3단계: OPEN (데이터 파일 + Redo Log 오픈)
ALTER DATABASE OPEN;

-- 정상 기동 (NOMOUNT → MOUNT → OPEN 전체 수행)
STARTUP;

-- RESTRICTED 모드로 기동 (RESTRICTED SESSION 권한자만 접속)
STARTUP RESTRICT;

-- FORCE 기동 (SHUTDOWN ABORT + STARTUP)
STARTUP FORCE;

-- 특정 PFILE을 지정하여 기동
STARTUP PFILE='/u01/app/oracle/dbs/initORCL.ora';

-- READ ONLY 모드로 기동
STARTUP MOUNT;
ALTER DATABASE OPEN READ ONLY;

-- UPGRADE 모드로 기동 (업그레이드 스크립트 실행용)
STARTUP UPGRADE;

-- NORMAL 종료 (모든 사용자 로그아웃 대기)
SHUTDOWN NORMAL;

-- TRANSACTIONAL 종료 (활성 트랜잭션 완료 대기)
SHUTDOWN TRANSACTIONAL;

-- IMMEDIATE 종료 (미완료 트랜잭션 롤백 후 종료 — 가장 권장)
SHUTDOWN IMMEDIATE;

-- ABORT 종료 (즉시 강제 종료 — 비상시만)
SHUTDOWN ABORT;

-- RESTRICTED 모드 활성화 (새 접속 제한)
ALTER SYSTEM ENABLE RESTRICTED SESSION;

-- RESTRICTED 모드 비활성화 (접속 허용)
ALTER SYSTEM DISABLE RESTRICTED SESSION;

-- 현재 RESTRICTED 상태 확인
SELECT logins FROM V$INSTANCE;

-- 특정 PDB 열기
ALTER PLUGGABLE DATABASE pdb1 OPEN;

-- 모든 PDB 열기
ALTER PLUGGABLE DATABASE ALL OPEN;

-- 특정 PDB READ ONLY로 열기
ALTER PLUGGABLE DATABASE pdb1 OPEN READ ONLY;

-- 특정 PDB 닫기
ALTER PLUGGABLE DATABASE pdb1 CLOSE IMMEDIATE;

-- 모든 PDB 닫기
ALTER PLUGGABLE DATABASE ALL CLOSE IMMEDIATE;

-- 특정 PDB 상태 저장 (CDB 재기동 시 자동 복원)
ALTER PLUGGABLE DATABASE pdb1 SAVE STATE;

-- 모든 PDB 상태 저장
ALTER PLUGGABLE DATABASE ALL SAVE STATE;

-- 저장된 상태 제거
ALTER PLUGGABLE DATABASE pdb1 DISCARD STATE;

-- 저장된 상태 확인
SELECT con_name, instance_name, state FROM DBA_PDB_SAVED_STATES;

-- PDB 컨텍스트로 전환
ALTER SESSION SET CONTAINER = pdb1;

-- PDB 컨텍스트에서 STARTUP (= PDB OPEN)
STARTUP;

-- PDB 컨텍스트에서 SHUTDOWN (= PDB CLOSE)
SHUTDOWN IMMEDIATE;

-- 현재 컨테이너 확인
SHOW CON_NAME;

-- 컨트롤 파일 경로 확인
SELECT name, value FROM V$PARAMETER WHERE name = 'control_files';

-- 컨트롤 파일 상세 정보
SELECT name, status, block_size, file_size_blks FROM V$CONTROLFILE;

-- 컨트롤 파일에 기록된 데이터 파일 정보
SELECT file#, name, status, checkpoint_change#, checkpoint_time FROM V$DATAFILE;

-- CDB 내 모든 컨테이너 조회 (CDB$ROOT, PDB$SEED, 사용자 PDB)
SELECT con_id, name, open_mode, restricted, application_root, application_pdb, total_size/1024/1024 AS total_size_mb FROM V$CONTAINERS ORDER BY con_id;

-- 컨테이너별 역할 확인
SELECT con_id, name, DECODE(con_id, 1, 'CDB$ROOT (Root)', 2, 'PDB$SEED (Seed)', 'User PDB') AS container_type, open_mode FROM V$CONTAINERS ORDER BY con_id;

-- PDB$SEED 상태 확인 (항상 READ ONLY여야 함)
SELECT con_id, name, open_mode, restricted FROM V$CONTAINERS WHERE name = 'PDB$SEED';

-- PDB$SEED의 데이터 파일 확인
SELECT con_id, file_id, tablespace_name, file_name, bytes/1024/1024 AS size_mb FROM CDB_DATA_FILES WHERE con_id = 2 ORDER BY file_id;

-- CDB 공유 자원: 제어파일 확인
SELECT name, status FROM V$CONTROLFILE;

-- CDB 공유 자원: 온라인 Redo 로그 확인
SELECT group#, thread#, sequence#, bytes/1024/1024 AS size_mb, status FROM V$LOG ORDER BY group#;

-- PDB 로컬 자원: 컨테이너별 데이터 파일 확인
SELECT con_id, file#, name, bytes/1024/1024 AS size_mb, status FROM V$DATAFILE ORDER BY con_id, file#;

-- UNDO 모드 확인 (LOCAL_UNDO_ENABLED)
SELECT property_name, property_value FROM DATABASE_PROPERTIES WHERE property_name = 'LOCAL_UNDO_ENABLED';

-- RAC 환경: 모든 인스턴스 상태 조회
SELECT inst_id, instance_name, host_name, version_full, status, database_status, startup_time FROM GV$INSTANCE ORDER BY inst_id;

-- 인스턴스별 SGA 크기 확인
SELECT inst_id, name, value/1024/1024 AS size_mb FROM GV$SGA ORDER BY inst_id, name;

-- 인터커넥트 정보 확인
SELECT inst_id, name, ip_address FROM GV$CLUSTER_INTERCONNECTS;

-- RAC 환경에서 PDB 서비스 상태 조회
SELECT inst_id, con_id, name, network_name, pdb FROM GV$SERVICES WHERE pdb IS NOT NULL ORDER BY con_id, inst_id;

-- 각 노드에서 PDB의 오픈 상태 확인
SELECT inst_id, con_id, name, open_mode, restricted FROM GV$PDBS ORDER BY con_id, inst_id;

-- 서비스별 세션 분포 확인
SELECT inst_id, service_name, count(*) AS session_count FROM GV$SESSION WHERE type = 'USER' GROUP BY inst_id, service_name ORDER BY inst_id;
